#include <stdio.h>
int main() {
    int N, T;
    scanf("%d %d", &N, &T);
    int S[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &S[i]);
    }
    long long count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            for (int k = j + 1; k < N; k++) {
                for (int l = k + 1; l < N; l++) {
                    if (S[i] + S[j] + S[k] + S[l] == T) {
                        count++;
                    }
                }
            }
        }
    }
    printf("%lld\n", count);
    return 0;
}

